"""브랜드 로고 레지스트리 — SVG data URI 매핑"""

# brand name (lowercase) → data:image/svg+xml;base64,... URI
BRAND_LOGOS: dict[str, str] = {
    "nike": "data:image/svg+xml;base64,",
    "gucci": "data:image/svg+xml;base64,",
    "hermes": "data:image/svg+xml;base64,",
    "maison kitsune": "data:image/svg+xml;base64,",
    "theory": "data:image/svg+xml;base64,",
    "wrangler": "data:image/svg+xml;base64,",
}

# 브랜드명 별칭 매핑 (다양한 표기 대응)
BRAND_ALIASES: dict[str, str] = {
    "nike": "nike",
    "나이키": "nike",
    "gucci": "gucci",
    "구찌": "gucci",
    "hermes": "hermes",
    "hermès": "hermes",
    "에르메스": "hermes",
    "maison kitsune": "maison kitsune",
    "maison kitsuné": "maison kitsune",
    "메종키츠네": "maison kitsune",
    "키츠네": "maison kitsune",
    "theory": "theory",
    "띠어리": "theory",
    "wrangler": "wrangler",
    "랭글러": "wrangler",
}

# 그리드 표시 순서 (9칸 채울 때 사용)
GRID_ORDER = ["gucci", "nike", "hermes", "maison kitsune", "theory", "wrangler"]


def get_brand_logo(brand_name: str) -> str | None:
    """브랜드명으로 로고 data URI를 반환한다. 없으면 None."""
    key = BRAND_ALIASES.get(brand_name.lower().strip(), brand_name.lower().strip())
    return BRAND_LOGOS.get(key)


def get_brand_key(brand_name: str) -> str | None:
    """브랜드명을 정규화된 키로 변환한다."""
    return BRAND_ALIASES.get(brand_name.lower().strip(), brand_name.lower().strip())


def get_grid_logos(selected_brand: str) -> list[str | None]:
    """9칸 그리드용 로고 목록을 반환한다. 선택된 브랜드를 첫 번째에 배치."""
    selected_key = get_brand_key(selected_brand)
    result: list[str | None] = []
    
    # 선택된 브랜드를 첫 번째에
    logo = get_brand_logo(selected_brand)
    if logo:
        result.append(logo)
    
    # 나머지 브랜드 채우기
    for key in GRID_ORDER:
        if key == selected_key:
            continue
        if key in BRAND_LOGOS:
            result.append(BRAND_LOGOS[key])
        if len(result) >= 9:
            break
    
    # 9개 미만이면 None으로 채움
    while len(result) < 9:
        result.append(None)
    
    return result[:9]
